import * as React from 'react';

import * as CheckboxPrimitive from '@radix-ui/react-checkbox';
import { cva, type VariantProps } from 'class-variance-authority';
import clsx from 'clsx';

import { CheckIcon, IndeterminateCheckIcon } from '../icons';
import { cn } from '../utils/cn';

const defaultCheckboxVariants = cva(
  [
    'peer shrink-0 rounded-sm border border-input outline-none',
    'focus-visible:ring-2',
    'disabled:cursor-not-allowed disabled:opacity-50',
    'data-[state=checked]:border-primary data-[state=checked]:bg-primary data-[state=checked]:text-primary-foreground',
    'data-[state=indeterminate]:border-primary data-[state=indeterminate]:bg-primary data-[state=indeterminate]:text-primary-foreground',
  ],
  {
    variants: {
      size: {
        md: 'size-4',
        lg: 'size-5',
      },
    },
    defaultVariants: {
      size: 'md',
    },
  }
);

// Icon needs to be 2px smaller than the container for the checkmark to fit and
// be centered
const iconSizeMap = {
  md: clsx('size-[14px]'),
  lg: clsx('size-[18px]'),
} as const;

/**
 * A control that allows the user to toggle between checked and not checked,
 * or an indeterminate state.
 */
function Checkbox({
  className,
  size: sizeProp,
  ...props
}: React.ComponentProps<typeof CheckboxPrimitive.Root> &
  VariantProps<typeof defaultCheckboxVariants>) {
  const size = sizeProp ?? 'md';
  const iconSizeClass = iconSizeMap[size];
  return (
    <CheckboxPrimitive.Root
      data-slot="checkbox"
      className={cn(defaultCheckboxVariants({ size }), className)}
      {...props}
    >
      <CheckboxPrimitive.Indicator
        data-slot="checkbox-indicator"
        className="grid place-content-center text-current transition-none"
      >
        {props.checked === 'indeterminate' ? (
          <IndeterminateCheckIcon
            className={iconSizeClass}
            data-testid="indeterminate-check-icon"
          />
        ) : (
          <CheckIcon className={iconSizeClass} data-testid="check-icon" />
        )}
      </CheckboxPrimitive.Indicator>
    </CheckboxPrimitive.Root>
  );
}

export { Checkbox };
